44	    /// Reorder an argument list so that labelled fields supplied out-of-order are
45	    /// in the correct order.
46	    ///
47	    pub fn reorder<A>(
48	        &self,
49	        arguments: &mut Vec<CallArg<A>>,
50	        location: SrcSpan,
51	        context: IncorrectArityContext,
52	    ) -> Result<(), Error> {
53	        let mut labelled_arguments_given = false;
54	        let mut seen_labels = HashSet::new();
55	        let mut unknown_labels = Vec::new();
56	        let number_of_arguments = arguments.len();
57	
58	        if self.arity as usize != arguments.len() {
59	            return Err(Error::IncorrectArity {
60	                labels: self.missing_labels(arguments),
61	                location,
62	                context,
63	                expected: self.arity as usize,
64	                given: arguments.len(),
65	            });
66	        }
67	
68	        for argument in arguments.iter() {
69	            match &argument.label {
70	                Some(_) => {
71	                    labelled_arguments_given = true;
72	                }
73	
74	                None => {
75	                    if labelled_arguments_given && !argument.is_implicit() {
76	                        return Err(Error::PositionalArgumentAfterLabelled {
77	                            location: argument.location,
78	                        });
79	                    }
80	                }
81	            }
82	        }
83	
84	        // Keeps track of which labelled arguments need to be inserted into which indices
85	        let mut labelled_arguments = HashMap::new();
86	
87	        // We iterate the argument in reverse order, because we have to remove elements
88	        // from the `args` list quite a lot, and removing from the end of a list is more
89	        // efficient than removing from the beginning or the middle.
90	        let mut i = arguments.len();
91	        while i > 0 {
92	            i -= 1;
93	            let (label, &location) =
94	                match &arguments.get(i).expect("Field indexing to get label").label {
95	                    // A labelled argument, we may need to reposition it
96	                    Some(l) => (
97	                        l,
98	                        &arguments
99	                            .get(i)
100	                            .expect("Indexing in labelled field reordering")
101	                            .location,
102	                    ),
103	
104	                    // Not a labelled argument
105	                    None => {
106	                        continue;
107	                    }
108	                };
109	
110	            let position = match self.fields.get(label) {
111	                None => {
112	                    unknown_labels.push((label.clone(), location));
113	                    continue;
114	                }
115	
116	                Some(&p) => p,
117	            };
118	
119	            if seen_labels.contains(label) {
120	                return Err(Error::DuplicateArgument {
121	                    location,
122	                    label: label.clone(),
123	                });
124	            }
125	            let _ = seen_labels.insert(label.clone());
126	
127	            // Add this argument to the `labelled_arguments` map, and remove if from the
128	            // existing arguments list. It will be reinserted later in the correct index
129	            let _ = labelled_arguments.insert(position as usize, arguments.remove(i));
130	        }
131	
132	        // The labelled arguments must be reinserted in order
133	        for i in 0..number_of_arguments {
134	            if let Some(argument) = labelled_arguments.remove(&i) {
135	                arguments.insert(i, argument);
136	            }
137	        }
138	
139	        if unknown_labels.is_empty() {
140	            Ok(())
141	        } else {
142	            Err(Error::UnknownLabels {
143	                valid: self.fields.keys().cloned().collect(),
144	                unknown: unknown_labels,
145	                supplied: seen_labels.into_iter().collect(),
146	            })
147	        }
148	    }
